# AutoGen ConversableAgent with RAG memory plugin.
# retrieve_relevant_msgs() fetches top-k past messages before each reply
# so the agent can reference facts from arbitrarily long conversations.

import autogen
from autogen.agentchat.contrib.retrieve_utils import (
    create_vector_db_from_dir,
    query_vector_db,
)

config_list = [{"model": "gpt-4o-mini", "api_key": "..."}]

class MemoryAgent(autogen.ConversableAgent):
    """ConversableAgent that injects retrieved memory into every system message."""

    def __init__(self, *args, memory_store, top_k=4, **kwargs):
        super().__init__(*args, **kwargs)
        self._memory_store = memory_store   # list of {"text": ..., "embedding": ...}
        self._top_k = top_k

    def generate_reply(self, messages=None, sender=None, **kwargs):
        if messages:
            query = messages[-1].get("content", "")
            hits = query_vector_db(
                query_texts=[query],
                n_results=self._top_k,
                client=self._memory_store,
                collection_name="agent_memory",
            )
            memory_ctx = "\n".join(d for d in hits["documents"][0] if d)
            # Prepend retrieved context to the last user message
            messages[-1]["content"] = (
                f"[Recalled memory]\n{memory_ctx}\n\n{messages[-1]['content']}"
            )
        return super().generate_reply(messages=messages, sender=sender, **kwargs)

assistant = MemoryAgent(
    name="MemoryAssistant",
    system_message="You are a project assistant with long-term memory.",
    llm_config={"config_list": config_list},
    memory_store=None,   # replace with actual Chroma/Qdrant client
)
